        public AIMemoryUnitTests()
        {
            DeleteFile(TestDBName);
            DeleteFile(BeatlesTestDBName);
        }

        [Fact()]
        [TestBeforeAfter]
        public void Basic_BM25()
        {
            var corpus = new List<IBm25Document>
            {
                new Bm25Document { Text = "the cat sat on the mat" },   // doc 0 – contains 'cat'
                new Bm25Document { Text = "the dog sat on the log" },   // doc 1 – no 'cat'
            };

            var bm25 = new Bm25(corpus);
            bm25.GetScores("cat on mat", corpus);
            Assert.True(corpus[0].Score > corpus[1].Score, "Doc containing 'cat' should outscore doc without it.");
        }

        const string outputFileName = @"c:\Brainshark\logs\bm25.log";
        void TraceBm25Score(string r) => File.AppendAllText(outputFileName, r + Environment.NewLine);

